fn main() {
    {
        let s = String::from("hello");
        println!("{}", s);
    } // s dropped here
    println!("scope ended");
}

fn main() {
    let s1 = String::from("hello");
    let s2 = s1;
    println!("{}", s1); // error: s1 moved
}

fn main() {
    let s1 = String::from("hello");
    let s2 = s1.clone();
    println!("s1={} s2={}", s1, s2);
}

fn main() {
    let x = 5;
    let y = x; // copy, not move
    println!("x={} y={}", x, y);
}

fn consume(s: String) {
    println!("{}", s);
}

fn main() {
    let s = String::from("hello");
    consume(s);
    // s is no longer valid
    println!("done");
}

fn make_greeting(name: &str) -> String {
    format!("Hello, {}!", name)
}

fn main() {
    let g = make_greeting("Rustacean");
    println!("{}", g);
}

fn main() {
    // Stack - copied
    let arr = [1, 2, 3]; // fixed size array: Copy
    let arr2 = arr;
    println!("{:?} {:?}", arr, arr2);

    // Heap - moved
    let v: Vec<i32> = vec![1, 2, 3];
    let v2 = v;
    // v is moved -- use v2
    println!("{:?}", v2);
}

fn main() {
    let s = String::from("I am owned");
    let s2 = s; // move: s2 is now the owner
    println!("{}", s2); // use s2
} // s2 dropped here — memory freed
